# ══════════════════════════════════════════════════════
# CARGA DEL SISTEMA CON MEMORIA PERSISTENTE
# ══════════════════════════════════════════════════════

@st.cache_resource(show_spinner=False)
def _load_system(memory_path: str):
    """
    Carga el agente UNA SOLA VEZ por proceso del servidor.
    La memoria se lee desde disco en el arranque y se actualiza
    en RAM tras cada turno. Se persiste a disco tras cada respuesta.
    """
    _d = os.path.dirname(os.path.abspath(__file__))
    if _d not in sys.path:
        sys.path.insert(0, _d)
    from agent_router import build_agent_executor, Memory, chat as _chat
    _mem  = Memory.load(memory_path)       # ← lee historial desde disco
    _exec, _mdl = build_agent_executor(_mem)
    return _exec, _mdl, _chat, _mem


# ── Inicialización del estado de sesión
if "messages" not in st.session_state:
    st.session_state.messages = []
if "ready" not in st.session_state:
    st.session_state.ready = False

if not st.session_state.ready:
    col = st.columns([1, 2, 1])[1]
    with col:
        st.markdown("""
        <div class="loading">
          <div style="font-size:2.8rem">⚙️</div>
          <h3>Iniciando sistema de Inteligencia Artificial</h3>
          <p>Cargando modelo de embeddings, ChromaDB y conexión con Gemini...</p>
        </div>
        """, unsafe_allow_html=True)
    try:
        with st.spinner(""):
            executor, active_model, chat_fn, memory = _load_system(MEMORY_PATH)
        st.session_state.executor     = executor
        st.session_state.active_model = active_model
        st.session_state.chat_fn      = chat_fn
        st.session_state.memory       = memory

        # Reconstruir historial de UI desde la memoria persistente
        # (así el chat muestra las conversaciones anteriores al recargar)
        if not st.session_state.messages:
            st.session_state.messages = memory.as_ui_messages()

        st.session_state.ready = True
        st.rerun()
    except Exception as e:
        st.error(f"❌ Error al iniciar: {e}")
        st.stop()

executor     = st.session_state.executor
active_model = st.session_state.active_model
chat_fn      = st.session_state.chat_fn
memory       = st.session_state.memory


